```class Solution {
public:
    int addMinimum(string word) {
        int countA = 0, countB = 0, countC = 0;
        for (char c : word) {
            if (c == 'a') countA++;
            else if (c == 'b') countB++;
            else countC++;
        }
        int minInsertions = countA + countB + countC;
        if (countA > countB) minInsertions += 2 * (countA - countB);
        if (countA > countC) minInsertions += 2 * (countA - countC);
        if (countB > countC) minInsertions += 2 * (countB - countC);
        return minInsertions;
    }
};
```

